    // Actually we process one sequence at a time, so per-sequence buffers: width + outputLen floats
    uint32_t perSeqBytes = (width + outputLen) * sizeof(float) + 32;
    uint32_t tileLen = 1;  // process one sequence per tile
    uint32_t numTiles = totalSequences;
    uint32_t blockDim = numTiles;
    if (blockDim < 8u) blockDim = 8u;
