#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;
constexpr int32_t ALIGN_ELEMS = 8;  // 32 bytes / sizeof(float)

class KernelCa6k00513Custom {
public:
    __aicore__ inline KernelCa6k00513Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalSequences, uint32_t width,
                                uint32_t kernelSize, uint32_t stride,
                                uint32_t padding, uint32_t outputLen,
                                uint32_t tileLen) {
        totalSequences_ = totalSequences;
        width_ = width;
        kernelSize_ = kernelSize;
        stride_ = stride;
        padding_ = padding;
        outputLen_ = outputLen;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalSequences * width);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalSequences * outputLen);

        uint32_t alignedWidth = AlignUp(width_, ALIGN_ELEMS);
        uint32_t alignedOutput = AlignUp(outputLen_, ALIGN_ELEMS);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, alignedWidth * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, alignedOutput * sizeof(float));
        pipe_.InitBuffer(maxBuf_, 1, sizeof(float));
    }

    __aicore__ inline void Process() {
        if (totalSequences_ == 0 || outputLen_ == 0) return;

        uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());
        uint32_t perBlock = (totalSequences_ + blockNum - 1) / blockNum;
        uint32_t startSeq = blockIdx * perBlock;
        uint32_t endSeq = startSeq + perBlock;
        if (startSeq >= totalSequences_) return;
        if (endSeq > totalSequences_) endSeq = totalSequences_;

        for (uint32_t seq = startSeq; seq < endSeq; ++seq) {
            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[seq * width_], width_);

            AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
            AscendC::LocalTensor<float> maxLocal = maxBuf_.AllocTensor<float>();

            for (uint32_t o = 0; o < outputLen_; ++o) {
                int32_t start = static_cast<int32_t>(o * stride_) - static_cast<int32_t>(padding_);
                maxLocal(0) = -std::numeric_limits<float>::max();
                for (uint32_t k = 0; k < kernelSize_; ++k) {
                    int32_t idx = start + static_cast<int32_t>(k);
                    if (idx >= 0 && idx < static_cast<int32_t>(width_)) {
                        if (xLocal(idx) > maxLocal(0)) {
                            maxLocal(0) = xLocal(idx);
                        }
                    }
                }
                yLocal(o) = maxLocal(0);
            }

            AscendC::DataCopy(yGm_[seq * outputLen_], yLocal, outputLen_);

            maxBuf_.FreeTensor(maxLocal);
            outQueueY_.FreeTensor(yLocal);
            inQueueX_.FreeTensor(xLocal);
        }
    }

private:
    __aicore__ static inline uint32_t AlignUp(uint32_t x, uint32_t a) {
        return (x + a - 1u) & ~(a - 1u);
    }

    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> maxBuf_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalSequences_ {0};
    uint32_t width_ {0};
    uint32_t kernelSize_ {0};
    uint32_t stride_ {0};
    uint32_t padding_ {0};
    uint32_t outputLen_ {0};
};

extern "C" __global__ __aicore__ void ca6k00513_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling) {
    GET_TILING_DATA(tiling_data, tiling);
    KernelCa6k00513Custom op;
    op.Init(x, y, tiling_data.totalSequences, tiling_data.width,
            tiling_data.kernelSize, tiling_data.stride,
            tiling_data.padding, tiling_data.outputLen,
            tiling_data.tileLen);
    op.Process();
}
